def priority(el: tuple, n: int, w: int) -> float:
    # Measure internal structure: deviation from uniform distribution of nonzeros
    nonzero_indices = [i for i, x in enumerate(el) if x != 0]
    if not nonzero_indices:
        return -float('inf')
    ideal_positions = [int(i * (n - 1) / (w - 1)) for i in range(w)] if w > 1 else [0]
    internal_score = -sum(abs(nonzero_indices[i] - ideal_positions[i]) for i in range(len(nonzero_indices)) if i < len(ideal_positions))
    # External compatibility penalty: sum of Hamming distances to already selected elements (simulated)
    # Since we don't have the set state, we estimate using global properties
    # penalty for having many 2's close together (conflict prone)
    twos = [i for i, x in enumerate(el) if x == 2]
    conflict_penalty = 0
    if len(twos) > 1:
        for i in range(len(twos) - 1):
            gap = twos[i+1] - twos[i]
            if gap <= 2:
                conflict_penalty += (3 - gap) * 2
