def priority(el: tuple, n: int, w: int) -> float:
    pos = [i for i, v in enumerate(el) if v != 0]
    if len(pos) < 2:
        return 0.0
    # Variance (spread measure)
    mean_pos = sum(pos) / len(pos)
    var = sum((p - mean_pos) ** 2 for p in pos) / len(pos)
    # Minimum distance penalty
    min_dist = min(abs(pos[i] - pos[j]) for i in range(len(pos)) for j in range(i+1, len(pos)))
    if min_dist == 0:
        dist_penalty = 1e6
    else:
        dist_penalty = 1.0 / min_dist
    # Alternating parity bonus
    sorted_pos = sorted(pos)
    alt_bonus = sum(1 for i in range(len(sorted_pos)-1) if sorted_pos[i] % 2 != sorted_pos[i+1] % 2)
    # Normalize variance by maximum possible (n-1)^2/4
    max_var = ((n-1)**2) / 4.0 if n > 1 else 1
    return (var / max_var) - dist_penalty + (alt_bonus / max(1, len(pos)))

