def priority(el: tuple, n: int, w: int) -> float:
    positions = [i for i, v in enumerate(el) if v != 0]
    if len(positions) < 2:
        return 0.0

    distances = []
    for i in range(len(positions)):
        for j in range(i+1, len(positions)):
            distances.append(abs(positions[i] - positions[j]))

    if not distances:
        return 0.0

    harmonic_sum = sum(1.0 / d for d in distances if d > 0)
    harmonic_mean = len(distances) / harmonic_sum if harmonic_sum > 0 else 0.0

    penalty = 0
    for i in range(len(positions)):
        for j in range(i+1, len(positions)):
            if abs(positions[i] - positions[j]) == 1:
                penalty += 2

    bonus = 0
    mid = (n - 1) / 2.0
    for p in positions:
        bonus += 0.5 if abs(p - mid) <= 1.0 else 0.0

    return harmonic_mean - penalty + bonus

def priority(el: tuple, n: int, w: int) -> float:
    positions = [i for i, v in enumerate(el) if v != 0]
    if len(positions) < 2:
        return 0.0

    # Sum of squared distances
    sq_dist_sum = 0.0
    for i in range(len(positions)):
        for j in range(i+1, len(positions)):
            d = abs(positions[i] - positions[j])
            sq_dist_sum += d * d

    # Penalty for positions too close to edges (first 2 or last 2 indices)
    edge_penalty = 0
    for p in positions:
        if p < 2 or p > n - 3:
            edge_penalty += 1.5

    # Gaussian reward for positions near center
    center = (n - 1) / 2.0
    gaussian_bonus = 0.0
    sigma = n / 6.0
    for p in positions:
        gaussian_bonus += 2.0 * (2.71828 ** (-((p - center) ** 2) / (2 * sigma * sigma)))

    return sq_dist_sum - edge_penalty + gaussian_bonus
